-- 005_n5_words_meiji
-- N5 單字匯入：明治神宮（CSV 行 344-685，共 342 字）
-- 資料源：stephenmk/yomitan-jlpt-vocab (CC-BY, Jonathan Waller / Tanos)
-- 中文翻譯：Claude（學生友善口語風格）

with new_words as (
  returning id, lemma
)
select
  (select id from shrines where slug = 'meiji'),
  nw.id,
  row_number() over (order by nw.lemma)
from new_words nw;
